# [SYSTEM: LEGACY_TUI | STATUS: ARCHIVE | DO NOT EXECUTE]
"""
Project storage system for conversation logs and future RAG integration.
Manages project-scoped conversation history and metadata.
"""
import json
import time
from pathlib import Path
from datetime import datetime
from typing import Dict, List, Optional, Any
from dataclasses import dataclass, asdict
import uuid
from .atomic_writer import AtomicWriter

@dataclass
class ProjectInfo:
    """Information about a project"""
    id: str
    name: str
    description: str
    created_at: str
    last_updated: str
    conversation_count: int = 0
    total_tokens: int = 0
    tags: List[str] = None

    def to_dict(self) -> Dict:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: Dict) -> 'ProjectInfo':
        return cls(**data)

@dataclass
class ConversationLog:
    """Single conversation entry for project storage"""
    id: str
    timestamp: str
    role: str  # "user" or "assistant"
    content: str
    metadata: Dict[str, Any] = None
    project_id: str = None
    tokens: int = 0

    def to_dict(self) -> Dict:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: Dict) -> 'ConversationLog':
        return cls(**data)

class ProjectStore:
    """
    Manages project storage with conversation logs and metadata.
    Designed to be RAG-ready with structured data storage.
    """

    def __init__(self, base_path: str = None):
        """Initialize project store with base storage path"""
        if base_path is None:
            base_path = str(Path.home() / ".opencode" / "projects")

        self.base_path = Path(base_path)
        self.base_path.mkdir(parents=True, exist_ok=True)

        # Initialize atomic writer with backup directory
        self.backup_dir = self.base_path / "backups"
        self.backup_dir.mkdir(parents=True, exist_ok=True)
        self.atomic_writer = AtomicWriter(str(self.backup_dir))

        self.current_project_id: Optional[str] = None
        self.projects: Dict[str, ProjectInfo] = {}

        # Load existing projects
        self._load_projects()

    def _load_projects(self):
        """Load all existing projects"""
        index_file = self.base_path / "projects.json"
        if index_file.exists():
            try:
                with open(index_file, 'r') as f:
                    data = json.load(f)
                    self.projects = {
                        pid: ProjectInfo.from_dict(pdata)
                        for pid, pdata in data.get('projects', {}).items()
                    }
                    self.current_project_id = data.get('current_project_id')
            except Exception as e:
                print(f"Warning: Could not load projects index: {e}")

    def _save_projects_index(self):
        """Save projects index using atomic writes"""
        index_file = self.base_path / "projects.json"
        try:
            data = {
                'current_project_id': self.current_project_id,
                'projects': {pid: pinfo.to_dict() for pid, pinfo in self.projects.items()}
            }
            success = self.atomic_writer.write_json_atomic(str(index_file), data)
            if not success:
                raise Exception("Atomic write failed")
        except Exception as e:
            print(f"Warning: Could not save projects index: {e}")
            # Fallback to non-atomic write
            try:
                with open(index_file, 'w') as f:
                    json.dump(data, f, indent=2)
            except Exception as fallback_error:
                print(f"Warning: Fallback save also failed: {fallback_error}")

    def create_project(self, name: str, description: str = "", tags: List[str] = None) -> str:
        """Create a new project and return its ID"""
        project_id = str(uuid.uuid4())[:8]  # Short ID
        project_info = ProjectInfo(
            id=project_id,
            name=name,
            description=description,
            created_at=datetime.now().isoformat(),
            last_updated=datetime.now().isoformat(),
            tags=tags or []
        )

        # Create project directory
        project_dir = self.base_path / project_id
        project_dir.mkdir(exist_ok=True)

        # Create subdirectories for future RAG use
        (project_dir / "logs").mkdir(exist_ok=True)
        (project_dir / "rag").mkdir(exist_ok=True)
        (project_dir / "exports").mkdir(exist_ok=True)

        # Save project info
        self.projects[project_id] = project_info
        self._save_projects_index()

        return project_id

    def select_project(self, project_id: str) -> bool:
        """Select a project as current"""
        if project_id in self.projects:
            self.current_project_id = project_id
            self._save_projects_index()
            return True
        return False

    def get_current_project(self) -> Optional[ProjectInfo]:
        """Get current project info"""
        if self.current_project_id and self.current_project_id in self.projects:
            return self.projects[self.current_project_id]
        return None

    def list_projects(self) -> List[ProjectInfo]:
        """List all projects"""
        return list(self.projects.values())

    def get_project_path(self, project_id: str) -> Path:
        """Get path to project directory"""
        return self.base_path / project_id

    def log_conversation(self, role: str, content: str, metadata: Dict[str, Any] = None,
                        project_id: str = None) -> str:
        """
        Log a conversation entry to the current or specified project.
        Returns the log entry ID.
        """
        target_project_id = project_id or self.current_project_id
        if not target_project_id:
            # Create default project if none exists
            target_project_id = self.create_project("default", "Default project")
            self.select_project(target_project_id)

        log_entry = ConversationLog(
            id=str(uuid.uuid4())[:12],
            timestamp=datetime.now().isoformat(),
            role=role,
            content=content,
            metadata=metadata or {},
            project_id=target_project_id,
            tokens=len(content.split())  # Rough token estimate
        )

        # Save to project log file using atomic append
        project_path = self.get_project_path(target_project_id)
        log_file = project_path / "logs" / "conversations.jsonl"

        try:
            success = self.atomic_writer.append_jsonl_atomic(str(log_file), log_entry.to_dict())
            if not success:
                raise Exception("Atomic append failed")

            # Update project stats
            if target_project_id in self.projects:
                project_info = self.projects[target_project_id]
                project_info.conversation_count += 1
                project_info.total_tokens += log_entry.tokens
                project_info.last_updated = datetime.now().isoformat()
                self._save_projects_index()

        except Exception as e:
            print(f"Warning: Could not log conversation: {e}")
            # Fallback to non-atomic append
            try:
                with open(log_file, 'a') as f:
                    f.write(json.dumps(log_entry.to_dict()) + '\n')
                # Still update stats on fallback
                if target_project_id in self.projects:
                    project_info = self.projects[target_project_id]
                    project_info.conversation_count += 1
                    project_info.total_tokens += log_entry.tokens
                    project_info.last_updated = datetime.now().isoformat()
                    self._save_projects_index()
            except Exception as fallback_error:
                print(f"Warning: Fallback conversation logging also failed: {fallback_error}")

        return log_entry.id

    def get_project_conversations(self, project_id: str, limit: int = None) -> List[ConversationLog]:
        """Get conversation logs for a project"""
        project_path = self.get_project_path(project_id)
        log_file = project_path / "logs" / "conversations.jsonl"

        conversations = []
        if log_file.exists():
            try:
                with open(log_file, 'r') as f:
                    lines = f.readlines()
                    if limit:
                        lines = lines[-limit:]  # Get recent entries

                    for line in lines:
                        if line.strip():
                            conv_data = json.loads(line.strip())
                            conversations.append(ConversationLog.from_dict(conv_data))
            except Exception as e:
                print(f"Warning: Could not load conversations: {e}")

        return conversations

    def export_project(self, project_id: str, export_path: str = None) -> str:
        """Export project data to a file"""
        if project_id not in self.projects:
            raise ValueError(f"Project {project_id} not found")

        project_info = self.projects[project_id]
        conversations = self.get_project_conversations(project_id)

        export_data = {
            'project_info': project_info.to_dict(),
            'conversations': [conv.to_dict() for conv in conversations],
            'exported_at': datetime.now().isoformat(),
            'export_version': '1.0'
        }

        if export_path is None:
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            export_path = str(self.base_path / project_id / "exports" / f"export_{timestamp}.json")

        Path(export_path).parent.mkdir(parents=True, exist_ok=True)
        with open(export_path, 'w') as f:
            json.dump(export_data, f, indent=2)

        return export_path

    def archive_project(self, project_id: str) -> bool:
        """Archive a project (mark as archived, don't delete)"""
        if project_id not in self.projects:
            return False

        project_info = self.projects[project_id]
        if 'archived' not in project_info.tags:
            project_info.tags.append('archived')
            project_info.last_updated = datetime.now().isoformat()
            self._save_projects_index()

        return True

    def get_storage_stats(self) -> Dict[str, Any]:
        """Get storage statistics"""
        total_size = 0
        total_conversations = 0
        total_tokens = 0

        for project_info in self.projects.values():
            total_conversations += project_info.conversation_count
            total_tokens += project_info.total_tokens

            # Calculate directory size
            project_path = self.get_project_path(project_info.id)
            if project_path.exists():
                for file_path in project_path.rglob('*'):
                    if file_path.is_file():
                        total_size += file_path.stat().st_size

        return {
            'total_projects': len(self.projects),
            'active_projects': len([p for p in self.projects.values() if 'archived' not in p.tags]),
            'total_conversations': total_conversations,
            'total_tokens': total_tokens,
            'storage_size_mb': total_size / (1024 * 1024),
            'base_path': str(self.base_path)
        }

# Global instance for easy access
project_store = ProjectStore()